// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "../../contracts/v2/interfaces/IUniswapV2Router02.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";

/**
 * Minimal mock of Uniswap V2 router + factory + pair for testing Aethpad v2.
 *
 * Pair is a dumb address that holds tokens + ETH and behaves like a constant-
 * product AMM for swaps. addLiquidityETH mints LP tokens to `to`. Pair tracks
 * reserves via balance checks.
 */

contract MockWETH {
    string public name = "Wrapped Ether";
    string public symbol = "WETH";
    uint8 public decimals = 18;
    function deposit() external payable {}
    function withdraw(uint256) external {}
}

contract MockUniswapV2Pair {
    address public token0;
    address public token1;
    mapping(address => uint256) public balanceOf;
    uint256 public totalSupply;
    function initialize(address _t0, address _t1) external { token0 = _t0; token1 = _t1; }
    function mint(address to, uint256 amount) external {
        balanceOf[to] += amount;
        totalSupply += amount;
    }
}

contract MockUniswapV2Factory {
    mapping(address => mapping(address => address)) public pairs;
    address public lastPair;

    function createPair(address a, address b) external returns (address) {
        require(pairs[a][b] == address(0), "exists");
        MockUniswapV2Pair p = new MockUniswapV2Pair();
        p.initialize(a, b);
        pairs[a][b] = address(p);
        pairs[b][a] = address(p);
        lastPair = address(p);
        return address(p);
    }

    function getPair(address a, address b) external view returns (address) {
        return pairs[a][b];
    }
}

contract MockUniswapV2Router {
    address public immutable _factory;
    address public immutable _weth;

    constructor(address factoryAddr, address wethAddr) {
        _factory = factoryAddr;
        _weth = wethAddr;
    }

    function factory() external view returns (address) { return _factory; }
    function WETH() external view returns (address) { return _weth; }

    function addLiquidityETH(
        address token,
        uint256 amountTokenDesired,
        uint256,
        uint256,
        address to,
        uint256
    ) external payable returns (uint256 amountToken, uint256 amountETH, uint256 liquidity) {
        // Pull tokens
        IERC20(token).transferFrom(msg.sender, address(this), amountTokenDesired);
        // "Mint" LP
        liquidity = amountTokenDesired + msg.value;
        amountToken = amountTokenDesired;
        amountETH = msg.value;
        // Register pair if not exists
        address pair = MockUniswapV2Factory(_factory).getPair(token, _weth);
        if (pair == address(0)) {
            pair = MockUniswapV2Factory(_factory).createPair(token, _weth);
        }
        MockUniswapV2Pair(pair).mint(to, liquidity);
        // Park tokens + ETH in this router as "pool" for later swaps
    }

    // Very simplified swap — treats this contract as the pool.
    function swapExactTokensForETHSupportingFeeOnTransferTokens(
        uint256 amountIn,
        uint256,
        address[] calldata path,
        address to,
        uint256
    ) external {
        address token = path[0];
        IERC20(token).transferFrom(msg.sender, address(this), amountIn);
        // Give back tiny fraction as ETH (mock price: 0.0001 ETH per token unit for test)
        uint256 ethOut = amountIn / 1e4; // dumb rate for test
        if (ethOut > address(this).balance) ethOut = address(this).balance;
        (bool ok, ) = payable(to).call{value: ethOut}("");
        require(ok, "send");
    }

    receive() external payable {}
}

contracts/v2/AethpadBondingCurveV2.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "./interfaces/IUniswapV2Router02.sol";

interface IAethpadTokenV2 {
    function transfer(address to, uint256 amount) external returns (bool);
    function approve(address spender, uint256 amount) external returns (bool);
    function balanceOf(address) external view returns (uint256);
    function depositEthReward() external payable;
    function depositEthPlatform() external payable;
    function burnFromCurve(uint256 amount) external;
    function notifyGraduated(address pair, address router) external;
}

/**
 * @title AethpadBondingCurveV2
 * @notice Virtual-reserve bonding curve with ETH-denominated tax split at the
 *         boundary. On buy, a portion of incoming ETH is skimmed to the token
 *         (for holder rewards) and to the factory (for platform fees) BEFORE
 *         the curve AMM math. On sell, the same skim happens on outgoing ETH.
 *
 *         Burn tax is in tokens (1.5% of token flow) to keep deflation on the
 *         supply itself.
 *
 *         Target: 5 ETH net real raised. Virtual ETH: 3 (for price floor).
 *         At graduation, curve adds LP to Uniswap V2 and burns the LP tokens
 *         forever. Pre-graduation, factory owner can force-close and withdraw.
 */
contract AethpadBondingCurveV2 is ReentrancyGuard {
    // ─── Constants ────────────────────────────────────────────────
    uint256 public constant CURVE_TOKEN_SUPPLY = 800_000_000 * 1e18;  // tokens for sale
    uint256 public constant GRAD_TOKEN_SUPPLY = 200_000_000 * 1e18;   // LP reserve
    uint256 public constant TARGET_REAL_ETH = 5 ether;
    uint256 public constant VIRTUAL_ETH = 3 ether;

    // Tax bps (same semantics as token)
    uint256 public constant BURN_BPS = 150;
    uint256 public constant REWARD_BPS = 200;
    uint256 public constant PLATFORM_BPS = 150;

    // Anti-snipe surcharges on sells (bps)
    uint256 public constant SNIPE_BPS_5MIN = 2000;
    uint256 public constant SNIPE_BPS_1HR = 1000;
    uint256 public constant SNIPE_BPS_24HR = 500;

    // ─── Immutables ────────────────────────────────────────────────
    IAethpadTokenV2 public token;
    address public immutable factory;
    address public immutable trustedInitializer;
    IUniswapV2Router02 public immutable uniswapRouter;
    IUniswapV2Factory public immutable uniswapFactory;

    // ─── State ─────────────────────────────────────────────────────
    uint256 public virtualTokenReserve;
    uint256 public realEthRaised;       // net real ETH raised for curve (after boundary taxes)
    bool public graduated;
    bool public forceClosed;            // set if factory owner withdraws pre-grad

    // Per-user last buy ts (for anti-snipe on sells)
    mapping(address => uint64) public lastBuyAt;

    // ─── Events ────────────────────────────────────────────────────
    event Buy(address indexed buyer, uint256 ethIn, uint256 ethForCurve, uint256 tokensOut, uint256 progressBps);
    event Sell(address indexed seller, uint256 tokensIn, uint256 ethOutGross, uint256 ethToUser, uint256 progressBps);
    event Graduated(uint256 ethToLp, uint256 tokensToLp, address pair);
    event ForceClosed(address indexed withdrawTo, uint256 ethAmount);

    // ─── Constructor ───────────────────────────────────────────────
    constructor(
        address _factory,
        address _uniswapRouter
    ) {
        factory = _factory;
        trustedInitializer = msg.sender; // Deployer (or Factory if direct)
        uniswapRouter = IUniswapV2Router02(_uniswapRouter);
        uniswapFactory = IUniswapV2Factory(IUniswapV2Router02(_uniswapRouter).factory());
        virtualTokenReserve = CURVE_TOKEN_SUPPLY;
    }

    function initToken(address _token) external {
        require(address(token) == address(0), "Already init");
        require(msg.sender == trustedInitializer || msg.sender == factory, "Only factory");
        token = IAethpadTokenV2(_token);
    }

    // ═════════════════════════════════════════════════════════════
    //  BUY — ETH in, tokens out
    // ═════════════════════════════════════════════════════════════

    /**
     * @notice Buy tokens with ETH. Splits the incoming ETH at the boundary:
     *   - REWARD_BPS → token.depositEthReward()   (holder rewards pool)
     *   - PLATFORM_BPS → token.depositEthPlatform() (fwd to factory owner)
     *   - remainder (including the BURN_BPS portion of value) → curve AMM buy
     * Then burns BURN_BPS of the tokens received (the "burn tax" on supply).
     *
     * Net effect: user sends 1 ETH, curve gets 0.965 ETH worth of tokens,
     * user receives 0.98875 × tokensFromCurveMath tokens (after 1.5% burn),
     * ETH holders/platform get their cuts in ETH.
     */
    function buy(uint256 minTokensOut) external payable nonReentrant returns (uint256 tokensToUser) {
        require(!graduated && !forceClosed, "Curve closed");
        require(msg.value > 0, "No ETH");

        uint256 ethIn = msg.value;

        // Boundary ETH split
        uint256 rewardEth = (ethIn * REWARD_BPS) / 10_000;
        uint256 platformEth = (ethIn * PLATFORM_BPS) / 10_000;
        uint256 ethForCurve = ethIn - rewardEth - platformEth;
        // Note: burn bps is NOT taken from ETH — it's taken from the token output

        // AMM math using ethForCurve
        uint256 ethReserveBefore = VIRTUAL_ETH + realEthRaised;
        uint256 k = ethReserveBefore * virtualTokenReserve;
        uint256 ethReserveAfter = ethReserveBefore + ethForCurve;
        uint256 tokenReserveAfter = k / ethReserveAfter;
        uint256 tokensOutGross = virtualTokenReserve - tokenReserveAfter;
        require(tokensOutGross > 0, "Too small");

        // Token-side burn tax
        uint256 burnTokens = (tokensOutGross * BURN_BPS) / 10_000;
        tokensToUser = tokensOutGross - burnTokens;
        require(tokensToUser >= minTokensOut, "Slippage");

        // State updates
        virtualTokenReserve = tokenReserveAfter;
        realEthRaised += ethForCurve;

        // Execute boundary ETH payments FIRST so the token contract can
        // credit the reward accumulator before user's balance changes.
        if (rewardEth > 0) {
            token.depositEthReward{value: rewardEth}();
        }
        if (platformEth > 0) {
            token.depositEthPlatform{value: platformEth}();
        }

        // Transfer tokens: burn portion to DEAD, rest to buyer
        if (burnTokens > 0) {
            token.burnFromCurve(burnTokens);
        }
        require(token.transfer(msg.sender, tokensToUser), "Token xfer failed");

        // Stamp last buy time for anti-snipe on this user
        lastBuyAt[msg.sender] = uint64(block.timestamp);

        emit Buy(msg.sender, ethIn, ethForCurve, tokensToUser, _progressBps());

        // Auto-graduate if target reached
        if (realEthRaised >= TARGET_REAL_ETH) {
            _graduate();
        }
    }

    // ═════════════════════════════════════════════════════════════
    //  SELL — tokens in, ETH out (with anti-snipe)
    // ═════════════════════════════════════════════════════════════

    function sell(uint256 tokenAmount, uint256 minEthOut) external nonReentrant returns (uint256 ethToUser) {
        require(!graduated && !forceClosed, "Curve closed");
        require(tokenAmount > 0, "No tokens");

        // Burn portion of input tokens up front
        uint256 burnTokens = (tokenAmount * BURN_BPS) / 10_000;
        uint256 tokensForCurve = tokenAmount - burnTokens;

        // Pull tokens from user into curve (curve holds them)
        // (requires approval)
        require(
            IERC20Like(address(token)).transferFrom(msg.sender, address(this), tokenAmount),
            "Transfer in failed"
        );
        // Forward burn portion via token.burnFromCurve (curve now holds tokens)
        if (burnTokens > 0) {
            token.burnFromCurve(burnTokens);
        }
        // Remaining `tokensForCurve` stay in curve, replenishing the reserve

        // AMM math on tokensForCurve
        uint256 ethReserveBefore = VIRTUAL_ETH + realEthRaised;
        uint256 k = ethReserveBefore * virtualTokenReserve;
        uint256 tokenReserveAfter = virtualTokenReserve + tokensForCurve;
        uint256 ethReserveAfter = k / tokenReserveAfter;
        uint256 ethOutGross = ethReserveBefore - ethReserveAfter;
        require(ethOutGross <= realEthRaised, "Insufficient ETH in curve");
        require(ethOutGross > 0, "Too small");

        virtualTokenReserve = tokenReserveAfter;
        realEthRaised -= ethOutGross;

        // Boundary split on OUTPUT ETH: rewards + platform + anti-snipe extra
        uint256 snipeBps = _antiSnipeBps(msg.sender);
        uint256 rewardEth = (ethOutGross * (REWARD_BPS + snipeBps)) / 10_000;
        uint256 platformEth = (ethOutGross * PLATFORM_BPS) / 10_000;
        ethToUser = ethOutGross - rewardEth - platformEth;
        require(ethToUser >= minEthOut, "Slippage");

        if (rewardEth > 0) {
            token.depositEthReward{value: rewardEth}();
        }
        if (platformEth > 0) {
            token.depositEthPlatform{value: platformEth}();
        }
        (bool ok, ) = payable(msg.sender).call{value: ethToUser}("");
        require(ok, "ETH send failed");

        emit Sell(msg.sender, tokenAmount, ethOutGross, ethToUser, _progressBps());
    }

    // ═════════════════════════════════════════════════════════════
    //  GRADUATION
    // ═════════════════════════════════════════════════════════════

    function _graduate() internal {
        graduated = true;

        uint256 ethForLp = address(this).balance;
        uint256 tokensForLp = GRAD_TOKEN_SUPPLY;
        // Curve also still holds any unsold CURVE_TOKEN_SUPPLY remainder; that
        // remainder becomes part of the LP seed (so the Uniswap price roughly
        // matches the final curve price).
        uint256 curveTokenBal = token.balanceOf(address(this));
        if (curveTokenBal < tokensForLp) {
            tokensForLp = curveTokenBal;
        }

        // Approve router
        require(IERC20Like(address(token)).approve(address(uniswapRouter), tokensForLp), "Approve failed");

        // Create pair if not exists
        address weth = uniswapRouter.WETH();
        address pair = uniswapFactory.getPair(address(token), weth);
        if (pair == address(0)) {
            pair = uniswapFactory.createPair(address(token), weth);
        }

        // Add liquidity, LP goes to DEAD (burned forever).
        // Use 99% minimums to prevent sandwich attacks at graduation
        // while tolerating minor Uniswap rounding.
        uint256 minTokensForLp = (tokensForLp * 99) / 100;
        uint256 minEthForLp    = (ethForLp * 99) / 100;
        uniswapRouter.addLiquidityETH{value: ethForLp}(
            address(token),
            tokensForLp,
            minTokensForLp,
            minEthForLp,
            0x000000000000000000000000000000000000dEaD,
            block.timestamp + 300
        );

        // If any tokens remain in curve (shouldn't, but defensive), burn them
        uint256 leftover = token.balanceOf(address(this));
        if (leftover > 0) {
            token.burnFromCurve(leftover);
        }

        // Notify token contract to enable post-grad tax logic
        token.notifyGraduated(pair, address(uniswapRouter));

        emit Graduated(ethForLp, tokensForLp, pair);
    }

    // ═════════════════════════════════════════════════════════════
    //  EMERGENCY: factory owner force close + withdraw
    // ═════════════════════════════════════════════════════════════

    /**
     * @notice Factory owner can pull ETH pre-graduation. Curve closes, no
     *         further trading. All remaining tokens are burned so they cannot
     *         be resold or remain stranded in the curve forever (fix #2).
     */
    function forceCloseAndWithdraw(address to) external nonReentrant {
        require(msg.sender == factory, "Only factory");
        require(!graduated, "Already graduated");
        forceClosed = true;

        // fix #2: burn all remaining tokens before withdrawing ETH
        uint256 tokenBal = token.balanceOf(address(this));
        if (tokenBal > 0) {
            token.burnFromCurve(tokenBal);
        }

        uint256 bal = address(this).balance;
        if (bal > 0) {
            (bool ok, ) = payable(to).call{value: bal}("");
            require(ok, "Withdraw failed");
        }
        emit ForceClosed(to, bal);
    }

    /**
     * @notice Factory stamps lastBuyAt for a user — used when factory performs
     *         the dev buy on behalf of the creator so anti-snipe applies to
     *         creator's actual address, not the factory (fix #1).
     */
    function stampBuyAt(address user) external {
        require(msg.sender == factory, "Only factory");
        lastBuyAt[user] = uint64(block.timestamp);
    }

    // ═════════════════════════════════════════════════════════════
    //  VIEWS
    // ═════════════════════════════════════════════════════════════

    function _progressBps() internal view returns (uint256) {
        if (graduated) return 10_000;
        return (realEthRaised * 10_000) / TARGET_REAL_ETH;
    }

    function progressBps() external view returns (uint256) {
        return _progressBps();
    }

    function _antiSnipeBps(address seller) internal view returns (uint256) {
        uint64 last = lastBuyAt[seller];
        if (last == 0) return 0;
        uint256 elapsed = block.timestamp - last;
        if (elapsed < 5 minutes) return SNIPE_BPS_5MIN;
        if (elapsed < 1 hours) return SNIPE_BPS_1HR;
        if (elapsed < 24 hours) return SNIPE_BPS_24HR;
        return 0;
    }

    function getBuyAmount(uint256 ethAmount) external view returns (uint256 tokensToUser) {
        if (graduated || forceClosed) return 0;
        uint256 ethForCurve = (ethAmount * (10_000 - REWARD_BPS - PLATFORM_BPS)) / 10_000;
        uint256 k = (VIRTUAL_ETH + realEthRaised) * virtualTokenReserve;
        uint256 tokenReserveAfter = k / (VIRTUAL_ETH + realEthRaised + ethForCurve);
        uint256 tokensOutGross = virtualTokenReserve - tokenReserveAfter;
        tokensToUser = tokensOutGross - (tokensOutGross * BURN_BPS) / 10_000;
    }

    function getSellAmount(uint256 tokenAmount, address seller) external view returns (uint256 ethToUser) {
        if (graduated || forceClosed) return 0;
        uint256 burnTokens = (tokenAmount * BURN_BPS) / 10_000;
        uint256 tokensForCurve = tokenAmount - burnTokens;
        uint256 k = (VIRTUAL_ETH + realEthRaised) * virtualTokenReserve;
        uint256 ethReserveAfter = k / (virtualTokenReserve + tokensForCurve);
        uint256 ethOutGross = (VIRTUAL_ETH + realEthRaised) - ethReserveAfter;
        if (ethOutGross > realEthRaised) ethOutGross = realEthRaised;
        uint256 snipeBps = _antiSnipeBps(seller);
        uint256 cut = (ethOutGross * (REWARD_BPS + snipeBps + PLATFORM_BPS)) / 10_000;
        ethToUser = ethOutGross > cut ? ethOutGross - cut : 0;
    }

    function currentPrice() external view returns (uint256) {
        uint256 ethReserve = VIRTUAL_ETH + realEthRaised;
        return (ethReserve * 1e18) / virtualTokenReserve;
    }

    receive() external payable {
        // Accept refunds from Uniswap router addLiquidity
    }
}

interface IERC20Like {
    function transferFrom(address from, address to, uint256 amount) external returns (bool);
    function approve(address spender, uint256 amount) external returns (bool);
}

contracts/v2/AethpadDeployer.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "./AethpadTokenV2.sol";
import "./AethpadBondingCurveV2.sol";

/**
 * @title AethpadDeployer
 * @notice Thin helper that deploys AethpadTokenV2 + AethpadBondingCurveV2
 *         pairs. Keeping deployment bytecode here lets the Factory stay
 *         under the 24KB contract size limit.
 */
contract AethpadDeployer {
    address public immutable factory;
    address public immutable uniswapRouter;

    constructor(address _factory, address _uniswapRouter) {
        factory = _factory;
        uniswapRouter = _uniswapRouter;
    }

    function deployPair(
        string calldata name,
        string calldata symbol
    ) external returns (address tokenAddr, address curveAddr) {
        require(msg.sender == factory, "Only factory");
        AethpadBondingCurveV2 curve = new AethpadBondingCurveV2(factory, uniswapRouter);
        curveAddr = address(curve);
        AethpadTokenV2 token = new AethpadTokenV2(name, symbol, factory, curveAddr);
        tokenAddr = address(token);
        curve.initToken(tokenAddr);
    }
}

contracts/v2/AethpadFactoryV2.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "./AethpadTokenV2.sol";
import "./AethpadBondingCurveV2.sol";
import "./AethpadDeployer.sol";

/**
 * @title AethpadFactoryV2
 * @notice Deploys AethpadTokenV2 + AethpadBondingCurveV2 atomically.
 *         Receives platform-fee ETH from all deployed tokens/curves.
 *         Owner can withdraw accumulated platform fees anytime.
 *         Owner can force-close any curve pre-graduation.
 */
contract AethpadFactoryV2 is Ownable, ReentrancyGuard {
    address public immutable uniswapRouter;
    AethpadDeployer public deployer;

    struct TokenRecord {
        address token;
        address curve;
        address creator;
        uint256 deployedAt;
        string metadataURI;           // off-chain pointer (logo, socials, description)
        uint256 initialDevBuyEth;
        uint256 initialDevBuyTokens;
    }

    mapping(address => TokenRecord) public records;  // token => record
    address[] public allTokens;

    uint256 public accumulatedPlatformFees;          // ETH accrued from all tokens
    uint256 public totalPlatformFeesWithdrawn;

    event TokenDeployed(
        address indexed token,
        address indexed curve,
        address indexed creator,
        string name,
        string symbol,
        string metadataURI,
        uint256 devBuyEth,
        uint256 devBuyTokens
    );
    event PlatformFeeReceived(address indexed fromToken, uint256 amount);
    event PlatformFeesWithdrawn(address indexed to, uint256 amount);
    event MetadataUpdated(address indexed token, string newURI);

    constructor(address _uniswapRouter) Ownable(msg.sender) {
        require(_uniswapRouter != address(0), "Bad router");
        uniswapRouter = _uniswapRouter;
    }

    function setDeployer(address _deployer) external onlyOwner {
        require(address(deployer) == address(0), "Already set");
        deployer = AethpadDeployer(_deployer);
    }

    // ═════════════════════════════════════════════════════════════
    //  TOKEN DEPLOYMENT
    // ═════════════════════════════════════════════════════════════

    /**
     * @notice Deploy a new token + curve. Free. Optionally include ETH for
     *         an atomic initial dev buy.
     */
    function createToken(
        string calldata name,
        string calldata symbol,
        string calldata metadataURI
    ) external payable nonReentrant returns (address tokenAddr, address curveAddr) {
        require(address(deployer) != address(0), "Deployer not set");
        (tokenAddr, curveAddr) = deployer.deployPair(name, symbol);
        AethpadTokenV2 token = AethpadTokenV2(payable(tokenAddr));
        AethpadBondingCurveV2 curve = AethpadBondingCurveV2(payable(curveAddr));

        // Record
        records[tokenAddr] = TokenRecord({
            token: tokenAddr,
            curve: curveAddr,
            creator: msg.sender,
            deployedAt: block.timestamp,
            metadataURI: metadataURI,
            initialDevBuyEth: 0,
            initialDevBuyTokens: 0
        });
        allTokens.push(tokenAddr);

        uint256 devBuyEth = msg.value;
        uint256 devBuyTokens = 0;

        // Optional initial dev buy (atomic)
        if (devBuyEth > 0) {
            devBuyTokens = curve.buy{value: devBuyEth}(0);
            // Note: `curve.buy` sends tokens to `msg.sender` of the call,
            // which in this context is this factory. Forward them to creator.
            // Actually — curve.buy uses msg.sender inside curve = this factory.
            // So tokens end up at factory. Forward to creator.
            uint256 received = token.balanceOf(address(this));
            if (received > 0) {
                token.transfer(msg.sender, received);
                devBuyTokens = received;
            }
            records[tokenAddr].initialDevBuyEth = devBuyEth;
            records[tokenAddr].initialDevBuyTokens = devBuyTokens;

            // fix #1: stamp lastBuyAt on the creator's address (not the factory)
            // so the anti-snipe penalty applies correctly if creator sells early.
            curve.stampBuyAt(msg.sender);
        }

        emit TokenDeployed(tokenAddr, curveAddr, msg.sender, name, symbol, metadataURI, devBuyEth, devBuyTokens);
    }

    // ═════════════════════════════════════════════════════════════
    //  METADATA UPDATE (creator-only)
    // ═════════════════════════════════════════════════════════════

    function updateMetadataURI(address tokenAddr, string calldata newURI) external {
        TokenRecord storage r = records[tokenAddr];
        require(r.creator == msg.sender, "Only creator");
        r.metadataURI = newURI;
        emit MetadataUpdated(tokenAddr, newURI);
    }

    // ═════════════════════════════════════════════════════════════
    //  PLATFORM FEE RECEIVE / WITHDRAW
    // ═════════════════════════════════════════════════════════════

    /**
     * @notice Accept ETH from any deployed token/curve as platform fee.
     *         We can't cheaply verify source here without a registry lookup;
     *         we simply accept and account.
     */
    receive() external payable {
        // If the caller is a registered token or curve, bucket it properly.
        // Otherwise, still accept but log as generic deposit.
        accumulatedPlatformFees += msg.value;
        emit PlatformFeeReceived(msg.sender, msg.value);
    }

    function withdrawPlatformFees(address to) external onlyOwner nonReentrant {
        uint256 amount = accumulatedPlatformFees;
        require(amount > 0, "Nothing to withdraw");
        require(to != address(0), "Bad recipient");
        accumulatedPlatformFees = 0;
        totalPlatformFeesWithdrawn += amount;
        (bool ok, ) = payable(to).call{value: amount}("");
        require(ok, "ETH send failed");
        emit PlatformFeesWithdrawn(to, amount);
    }

    // ═════════════════════════════════════════════════════════════
    //  ADMIN: per-token force close + per-token config
    // ═════════════════════════════════════════════════════════════

    function forceCloseCurve(address tokenAddr, address to) external onlyOwner {
        TokenRecord storage r = records[tokenAddr];
        require(r.curve != address(0), "Unknown token");
        AethpadBondingCurveV2(payable(r.curve)).forceCloseAndWithdraw(to);
    }

    function setTokenSwapThreshold(address tokenAddr, uint256 newThreshold) external onlyOwner {
        TokenRecord storage r = records[tokenAddr];
        require(r.token != address(0), "Unknown token");
        AethpadTokenV2(payable(r.token)).setSwapThreshold(newThreshold);
    }

    function setTokenExcluded(address tokenAddr, address account, bool excluded) external onlyOwner {
        TokenRecord storage r = records[tokenAddr];
        require(r.token != address(0), "Unknown token");
        AethpadTokenV2(payable(r.token)).setExcluded(account, excluded);
    }

    /**
     * @notice Set the keeper address for a token's push reward distribution.
     *         Pass address(0) to disable push (holders must claim manually).
     *         The keeper wallet should be funded from platform fees to cover gas.
     */
    function setTokenKeeper(address tokenAddr, address newKeeper) external onlyOwner {
        TokenRecord storage r = records[tokenAddr];
        require(r.token != address(0), "Unknown token");
        AethpadTokenV2(payable(r.token)).setKeeper(newKeeper);
    }

    /**
     * @notice Flush any platform ETH that the token contract was unable to
     *         forward (e.g., if factory receive() temporarily failed).
     */
    function flushTokenPlatformEth(address tokenAddr) external onlyOwner {
        TokenRecord storage r = records[tokenAddr];
        require(r.token != address(0), "Unknown token");
        AethpadTokenV2(payable(r.token)).withdrawPendingPlatform();
    }

    // ═════════════════════════════════════════════════════════════
    //  VIEWS
    // ═════════════════════════════════════════════════════════════

    function getAllTokens() external view returns (address[] memory) {
        return allTokens;
    }

    function allTokensLength() external view returns (uint256) {
        return allTokens.length;
    }

    function getRecord(address tokenAddr) external view returns (TokenRecord memory) {
        return records[tokenAddr];
    }
}

contracts/v2/AethpadTokenV2.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "./interfaces/IUniswapV2Router02.sol";

/**
 * @title AethpadTokenV2
 * @notice FIRE-inspired ERC-20 with time-weighted holder rewards paid in ETH.
 *
 *  PHASES
 *  ------
 *  Pre-graduation:
 *    All trades go through the bonding curve. The curve splits ETH at the
 *    entry/exit boundary and pushes the rewards/platform ETH portions into
 *    this token contract via `depositEthReward()` / `depositEthPlatform()`.
 *    The curve also calls `burnTokens()` for the burn portion.
 *    No ERC-20 tax is applied inside `_update` during this phase.
 *
 *  Post-graduation:
 *    Trades happen on Uniswap V2. This contract intercepts transfers to/from
 *    the Uniswap pair inside `_update` and takes tax in tokens. Tokens
 *    accumulate until a threshold, then a single batched swap converts them
 *    to ETH which is split into rewards/platform and distributed.
 *
 *  REWARDS
 *  -------
 *  Time-weighted: holdScore = balance * secondsHeld. Cumulative ETH per
 *  score is tracked, users claim pending ETH. Selling proportionally resets
 *  holdScore. No keeper needed — accrual updates on every transfer.
 *
 *  ANTI-SNIPE
 *  ----------
 *  Sells within the first 24 hours of last buy incur an extra surcharge
 *  that goes entirely to the rewards pool:
 *    <5 min:  +20%
 *    <1 hr:   +10%
 *    <24 hr:   +5%
 *    >=24 hr:   0%
 */
contract AethpadTokenV2 is ERC20, ReentrancyGuard {
    // ─── Constants ────────────────────────────────────────────────
    uint256 public constant TOTAL_SUPPLY = 1_000_000_000 * 1e18;
    uint256 public constant CURVE_SUPPLY = 800_000_000 * 1e18;
    uint256 public constant GRAD_SUPPLY = 200_000_000 * 1e18;

    // Tax basis points (out of 10000)
    uint256 public constant BURN_BPS = 150;      // 1.5%
    uint256 public constant REWARD_BPS = 200;    // 2.0%
    uint256 public constant PLATFORM_BPS = 150;  // 1.5%
    uint256 public constant TOTAL_TAX_BPS = BURN_BPS + REWARD_BPS + PLATFORM_BPS; // 500 (5%)

    // Anti-snipe surcharges (bps, on top of base; sent entirely to rewards pool)
    uint256 public constant SNIPE_BPS_5MIN = 2000;  // +20%
    uint256 public constant SNIPE_BPS_1HR = 1000;   // +10%
    uint256 public constant SNIPE_BPS_24HR = 500;   // +5%

    address public constant DEAD = 0x000000000000000000000000000000000000dEaD;

    // ─── Immutables (set once) ────────────────────────────────────
    address public immutable factory;   // AethpadFactoryV2
    address public immutable curve;     // AethpadBondingCurveV2

    // ─── Graduation / Uniswap state ───────────────────────────────
    bool public graduated;
    address public uniswapPair;
    IUniswapV2Router02 public uniswapRouter;

    // Threshold of token balance held by this contract before triggering swap
    uint256 public swapThreshold = 100_000 * 1e18;
    bool private _swapping;

    // ─── Hold score bookkeeping ───────────────────────────────────
    struct Checkpoint {
        uint128 balance;               // balance at last checkpoint
        uint64 lastUpdate;             // timestamp of last update
        uint64 lastBuyAt;              // timestamp of last buy (for anti-snipe)
        uint256 accumulatedScore;      // balance*seconds accrued up to lastUpdate
        uint256 ethPerScorePaid;       // reward accumulator snapshot at last settle
        uint256 pendingEth;            // unclaimed ETH rewards
    }
    mapping(address => Checkpoint) public checkpoints;

    uint256 public totalAccumulatedScore;   // sum of all accumulatedScore (settled-to-now lazily)
    uint256 public totalLastUpdate;         // ts of last settle on the global sum
    uint256 public totalSettledBalance;     // sum of all checkpoint balances (for settling total)

    uint256 public cumulativeEthPerScore;   // scaled 1e18
    uint256 public lastRewardTimestamp;     // block.timestamp of last cumulativeEthPerScore update

    // Addresses excluded from TAX logic (curve, factory, this, dead)
    // NOTE: uniswapPair is intentionally NOT in this mapping post-grad so tax fires on swaps.
    //       But it IS excluded from reward tracking via _isTracked().
    mapping(address => bool) public isExcluded;

    // Accumulated reward ETH deposited before any holders existed (rolled in on next deposit)
    uint256 public orphanedRewardEth;

    // Authorized keeper — the only address allowed to call pushRewards()
    // Set once by factory; can be updated by factory owner.
    address public keeper;

    // Maximum holders per pushRewards batch (fix #5: prevent OOG)
    uint256 public constant MAX_PUSH_BATCH = 150;

    // ─── Events ───────────────────────────────────────────────────
    event Graduated(address indexed pair);
    event RewardsDeposited(uint256 ethAmount, uint256 newCumulative);
    event RewardsClaimed(address indexed user, uint256 ethAmount);
    event RewardsPushed(uint256 holderCount, uint256 totalEthSent);
    event TaxTaken(address indexed from, address indexed to, uint256 burnAmt, uint256 rewardAmt, uint256 platformAmt);
    event PlatformFeeForwarded(uint256 ethAmount);
    event KeeperUpdated(address indexed oldKeeper, address indexed newKeeper);
    event ScoreDesyncDetected(address indexed user, uint256 drop, uint256 totalScore); // fix #6

    // ─── Constructor ──────────────────────────────────────────────
    constructor(
        string memory _name,
        string memory _symbol,
        address _factory,
        address _curve
    ) ERC20(_name, _symbol) {
        factory = _factory;
        curve = _curve;

        // Set exclusions BEFORE minting so the initial mint does not
        // register the curve in totalSettledBalance or hold-score tracking.
        // If exclusions come after _mint, the curve is briefly tracked and
        // picks up 1 billion tokens in totalSettledBalance — permanently
        // diluting all reward distributions.
        isExcluded[_curve] = true;
        isExcluded[_factory] = true;
        isExcluded[DEAD] = true;
        isExcluded[address(this)] = true;
        isExcluded[address(0)] = true;

        totalLastUpdate = block.timestamp;

        // Mint full supply to the curve (curve holds both CURVE_SUPPLY for sale
        // and GRAD_SUPPLY reserved for graduation LP)
        _mint(_curve, TOTAL_SUPPLY);
    }

    // ─── Modifiers ────────────────────────────────────────────────
    modifier onlyCurve() {
        require(msg.sender == curve, "Only curve");
        _;
    }

    modifier onlyFactory() {
        require(msg.sender == factory, "Only factory");
        _;
    }

    // ═════════════════════════════════════════════════════════════
    //  CURVE INTEGRATION (pre-graduation ETH-split tax path)
    // ═════════════════════════════════════════════════════════════

    /**
     * @notice Curve deposits ETH earmarked for holder rewards.
     *         Updates cumulative reward accumulator.
     */
    function depositEthReward() external payable onlyCurve {
        _creditRewardPool(msg.value);
    }

    // Platform ETH that could not be forwarded to factory (accumulated for retry)
    uint256 public pendingPlatformEth;

    /**
     * @notice Curve deposits ETH earmarked for platform. Immediately forwards
     *         to factory. If the factory call fails (edge case), parks ETH in
     *         pendingPlatformEth so trades are never bricked. Owner can later
     *         call withdrawPendingPlatform() to recover it.
     */
    function depositEthPlatform() external payable onlyCurve {
        if (msg.value == 0) return;
        (bool ok, ) = payable(factory).call{value: msg.value}("");
        if (ok) {
            emit PlatformFeeForwarded(msg.value);
        } else {
            // Park rather than revert — a factory receive() failure must never
            // permanently prevent buys/sells on this token.
            pendingPlatformEth += msg.value;
        }
    }

    /**
     * @notice Allows factory owner (via factory) to flush any parked platform ETH.
     */
    function withdrawPendingPlatform() external onlyFactory {
        uint256 amount = pendingPlatformEth;
        require(amount > 0, "Nothing pending");
        pendingPlatformEth = 0;
        (bool ok, ) = payable(factory).call{value: amount}("");
        require(ok, "ETH send failed");
        emit PlatformFeeForwarded(amount);
    }

    /**
     * @notice Curve requests burn of `amount` tokens held by curve.
     *         Curve must hold the tokens; we transfer from curve to DEAD.
     */
    function burnFromCurve(uint256 amount) external onlyCurve {
        if (amount > 0) {
            _transfer(curve, DEAD, amount);
        }
    }

    // ═════════════════════════════════════════════════════════════
    //  GRADUATION
    // ═════════════════════════════════════════════════════════════

    /**
     * @notice Called by curve when it has added LP to Uniswap and burned it.
     *         Enables post-graduation tax path on pair transfers.
     */
    function notifyGraduated(address _pair, address _router) external onlyCurve {
        require(!graduated, "Already graduated");
        graduated = true;
        uniswapPair = _pair;
        uniswapRouter = IUniswapV2Router02(_router);
        isExcluded[_pair] = false; // pair is taxable (it IS the tax boundary)
        emit Graduated(_pair);
    }

    // ═════════════════════════════════════════════════════════════
    //  ERC-20 OVERRIDE (holdScore + post-grad tax)
    // ═════════════════════════════════════════════════════════════

    function _update(address from, address to, uint256 value) internal override {
        // Settle rewards for both sides before balance changes
        _settleUser(from);
        _settleUser(to);

        // Pre-grad: no ERC-20-level tax (curve handled it at ETH boundary)
        // Post-grad: apply tax on pair transfers (swaps on Uniswap)
        if (graduated && !_swapping && !isExcluded[from] && !isExcluded[to]) {
            bool isBuy = (from == uniswapPair);
            bool isSell = (to == uniswapPair);

            if (isBuy || isSell) {
                uint256 extraBps = 0;
                if (isSell) {
                    extraBps = _antiSnipeExtraBps(from);
                }
                uint256 totalBps = TOTAL_TAX_BPS + extraBps;
                uint256 taxTokens = (value * totalBps) / 10_000;
                uint256 burnAmt = (value * BURN_BPS) / 10_000;

                // Send burn immediately
                if (burnAmt > 0) {
                    super._update(from, DEAD, burnAmt);
                }
                // Rest (reward + platform + anti-snipe extra) held by this contract
                uint256 heldTax = taxTokens - burnAmt;
                if (heldTax > 0) {
                    super._update(from, address(this), heldTax);
                }
                value -= taxTokens;

                // Update lastBuyAt for buyer
                if (isBuy) {
                    checkpoints[to].lastBuyAt = uint64(block.timestamp);
                }

                emit TaxTaken(from, to, burnAmt, 0, 0);
            }
        }

        // Actual transfer of (possibly reduced) value
        super._update(from, to, value);

        // Update holdScore checkpoints AFTER the transfer
        _updateCheckpoint(from);
        _updateCheckpoint(to);

        // Trigger swap-and-distribute if threshold met (post-grad only)
        if (
            graduated &&
            !_swapping &&
            from != uniswapPair &&
            balanceOf(address(this)) >= swapThreshold &&
            address(uniswapRouter) != address(0)
        ) {
            _swapAndDistribute();
        }
    }

    // ═════════════════════════════════════════════════════════════
    //  HOLD SCORE INTERNALS
    // ═════════════════════════════════════════════════════════════

    function _isTracked(address user) internal view returns (bool) {
        if (user == address(0)) return false;
        if (isExcluded[user]) return false;
        // Post-graduation: exclude the Uniswap pair from reward tracking.
        // The pair is NOT in isExcluded (so tax fires on swaps), but it must
        // not accumulate hold score — its pendingEth would be unclaimable forever.
        if (uniswapPair != address(0) && user == uniswapPair) return false;
        return true;
    }

    /**
     * @notice Settle a user's pending ETH rewards based on current accumulator.
     *         Called before any balance change so we use pre-change holdScore.
     *
     *         IMPORTANT: When computing the reward delta, we cap the user's
     *         hold score to `lastRewardTimestamp` — the moment the last reward
     *         was deposited. Without this cap, a user settling after a reward
     *         deposit would use a score that includes time AFTER the deposit,
     *         causing pendingEth to exceed the actual ETH deposited (reverts on send).
     *         The accumulated score is still extended to block.timestamp so future
     *         rewards accumulate correctly.
     */
    function _settleUser(address user) internal {
        if (!_isTracked(user)) return;
        Checkpoint storage c = checkpoints[user];

        uint256 delta = cumulativeEthPerScore - c.ethPerScorePaid;
        if (delta > 0) {
            // Cap score to lastRewardTimestamp to prevent over-claiming
            uint256 capTs = lastRewardTimestamp > c.lastUpdate
                ? lastRewardTimestamp
                : c.lastUpdate;
            uint256 cappedElapsed = capTs - c.lastUpdate;
            uint256 cappedScore = c.accumulatedScore + uint256(c.balance) * cappedElapsed;
            if (cappedScore > 0) {
                c.pendingEth += (cappedScore * delta) / 1e18;
            }
            c.ethPerScorePaid = cumulativeEthPerScore;
        }

        // Extend accumulatedScore to block.timestamp for future reward epochs.
        uint256 elapsed = block.timestamp - c.lastUpdate;
        c.accumulatedScore += uint256(c.balance) * elapsed;
        c.lastUpdate = uint64(block.timestamp);
    }

    /**
     * @notice After a transfer, refresh the user's checkpoint. Also updates
     *         the global totalAccumulatedScore running sum.
     */
    function _updateCheckpoint(address user) internal {
        if (!_isTracked(user)) return;
        Checkpoint storage c = checkpoints[user];

        // Settle the global total up to now using OLD balance snapshot
        _settleGlobalTotal();

        uint256 newBal = balanceOf(user);
        uint256 oldBal = uint256(c.balance);

        if (newBal < oldBal && oldBal > 0) {
            // Proportional holdScore reset on outflow: score scales by newBal/oldBal
            uint256 newScore = (c.accumulatedScore * newBal) / oldBal;
            // Adjust global by the DROP
            uint256 drop = c.accumulatedScore - newScore;
            if (totalAccumulatedScore >= drop) {
                totalAccumulatedScore -= drop;
            } else {
                // fix #6: emit desync event instead of silently flooring to 0
                emit ScoreDesyncDetected(user, drop, totalAccumulatedScore);
                totalAccumulatedScore = 0;
            }
            c.accumulatedScore = newScore;
        }

        // Update settled balance tracker
        if (newBal > oldBal) {
            totalSettledBalance += (newBal - oldBal);
        } else if (newBal < oldBal) {
            uint256 diff = oldBal - newBal;
            totalSettledBalance = totalSettledBalance >= diff ? totalSettledBalance - diff : 0;
        }

        c.balance = uint128(newBal);
        c.lastUpdate = uint64(block.timestamp);

        // If this is a BUY (from curve pre-grad, or from pair post-grad), stamp lastBuyAt
        // (post-grad pair buys are stamped in _update; here we stamp curve buys)
        if (!graduated && newBal > oldBal && msg.sender == curve) {
            c.lastBuyAt = uint64(block.timestamp);
        }
    }

    /**
     * @notice Extend the running totalAccumulatedScore up to block.timestamp
     *         using the current totalSettledBalance.
     */
    function _settleGlobalTotal() internal {
        uint256 elapsed = block.timestamp - totalLastUpdate;
        if (elapsed > 0 && totalSettledBalance > 0) {
            totalAccumulatedScore += totalSettledBalance * elapsed;
        }
        totalLastUpdate = block.timestamp;
    }

    function _creditRewardPool(uint256 ethAmount) internal {
        if (ethAmount == 0) return;
        _settleGlobalTotal();

        uint256 liveTotal = totalAccumulatedScore;
        if (liveTotal == 0) {
            // No holders yet — park ETH until someone holds tokens.
            orphanedRewardEth += ethAmount;
            emit RewardsDeposited(ethAmount, cumulativeEthPerScore);
            return;
        }

        // Roll in any previously orphaned ETH together with this tranche.
        uint256 poolEth = ethAmount + orphanedRewardEth;
        if (orphanedRewardEth > 0) orphanedRewardEth = 0;

        // fix #3: if poolEth is too small relative to liveTotal the division
        // rounds to 0 — ETH would be deposited but permanently unclaimable.
        // Park it as orphaned instead so it is swept in the next deposit.
        uint256 increment = (poolEth * 1e18) / liveTotal;
        if (increment == 0) {
            orphanedRewardEth += poolEth;
            emit RewardsDeposited(poolEth, cumulativeEthPerScore);
            return;
        }

        cumulativeEthPerScore += increment;
        lastRewardTimestamp = block.timestamp;
        emit RewardsDeposited(poolEth, cumulativeEthPerScore);
    }

    function _antiSnipeExtraBps(address seller) internal view returns (uint256) {
        uint64 lastBuy = checkpoints[seller].lastBuyAt;
        if (lastBuy == 0) return 0;
        uint256 elapsed = block.timestamp - lastBuy;
        if (elapsed < 5 minutes) return SNIPE_BPS_5MIN;
        if (elapsed < 1 hours) return SNIPE_BPS_1HR;
        if (elapsed < 24 hours) return SNIPE_BPS_24HR;
        return 0;
    }

    // ═════════════════════════════════════════════════════════════
    //  POST-GRAD SWAP-AND-DISTRIBUTE
    // ═════════════════════════════════════════════════════════════

    function _swapAndDistribute() internal {
        _swapping = true;

        uint256 tokenAmount = balanceOf(address(this));
        if (tokenAmount == 0) {
            _swapping = false;
            return;
        }

        // Swap tokens -> ETH via Uniswap
        address[] memory path = new address[](2);
        path[0] = address(this);
        path[1] = uniswapRouter.WETH();

        _approve(address(this), address(uniswapRouter), tokenAmount);

        // fix #4: compute 90% of expected output to guard against sandwich attacks
        uint256 minOut = 0;
        try uniswapRouter.getAmountsOut(tokenAmount, path) returns (uint256[] memory amounts) {
            minOut = (amounts[1] * 90) / 100;
        } catch {}

        uint256 ethBefore = address(this).balance;
        try uniswapRouter.swapExactTokensForETHSupportingFeeOnTransferTokens(
            tokenAmount,
            minOut,
            path,
            address(this),
            block.timestamp
        ) {
            uint256 ethReceived = address(this).balance - ethBefore;
            if (ethReceived > 0) {
                // Split: rewards vs platform, using their post-grad ratio.
                // Post-grad tax = 2% rewards + 1.5% platform (burn already in tokens).
                // Ratio 2 : 1.5 = 4 : 3 → 4/7 rewards, 3/7 platform
                uint256 platformEth = (ethReceived * 3) / 7;
                uint256 rewardEth = ethReceived - platformEth;

                if (platformEth > 0) {
                    (bool ok, ) = payable(factory).call{value: platformEth}("");
                    // If factory call fails, leave ETH here; try next time
                    if (ok) emit PlatformFeeForwarded(platformEth);
                }

                _creditRewardPool(rewardEth);
            }
        } catch {
            // Swap failed — tokens stay, try next time. No revert to not block transfers.
        }

        _swapping = false;
    }

    // ═════════════════════════════════════════════════════════════
    //  PUBLIC USER FUNCTIONS
    // ═════════════════════════════════════════════════════════════

    /**
     * @notice Claim pending ETH rewards manually (pull model, always available).
     */
    function claim() external nonReentrant {
        _settleUser(msg.sender);
        Checkpoint storage c = checkpoints[msg.sender];
        uint256 amount = c.pendingEth;
        require(amount > 0, "Nothing to claim");
        c.pendingEth = 0;
        (bool ok, ) = payable(msg.sender).call{value: amount}("");
        require(ok, "ETH send failed");
        emit RewardsClaimed(msg.sender, amount);
    }

    /**
     * @notice Automatic push distribution — called by the off-chain keeper
     *         (GitHub Actions cron) to push pending ETH rewards to a batch
     *         of holders without them needing to claim.
     *
     *         Only the keeper address can call this. The keeper wallet is
     *         funded from the platform fee and pays the gas cost.
     *
     *         If an ETH send to a holder fails (e.g. a contract that rejects
     *         ETH), that holder's pendingEth is left intact — they can still
     *         call claim() manually.
     *
     * @param holders  List of holder addresses to push rewards to.
     */
    function pushRewards(address[] calldata holders) external nonReentrant {
        require(msg.sender == keeper, "Only keeper");
        require(holders.length <= MAX_PUSH_BATCH, "Batch too large"); // fix #5
        uint256 totalSent;
        uint256 pushed;

        for (uint256 i = 0; i < holders.length; i++) {
            address holder = holders[i];
            if (!_isTracked(holder)) continue;

            _settleUser(holder);
            Checkpoint storage c = checkpoints[holder];
            uint256 amount = c.pendingEth;
            if (amount == 0) continue;

            c.pendingEth = 0;
            (bool ok, ) = payable(holder).call{value: amount}("");
            if (ok) {
                totalSent += amount;
                pushed++;
                emit RewardsClaimed(holder, amount);
            } else {
                // Restore pending so holder can claim() manually
                c.pendingEth = amount;
            }
        }

        emit RewardsPushed(pushed, totalSent);
    }

    // ═════════════════════════════════════════════════════════════
    //  VIEWS
    // ═════════════════════════════════════════════════════════════

    function pendingRewards(address user) external view returns (uint256) {
        if (!_isTracked(user)) return 0;
        Checkpoint storage c = checkpoints[user];
        uint256 delta = cumulativeEthPerScore - c.ethPerScorePaid;
        uint256 extra = 0;
        if (delta > 0) {
            // Mirror the capped-score logic from _settleUser so the view
            // returns the exact amount that will be paid on claim/push.
            uint256 capTs = lastRewardTimestamp > c.lastUpdate
                ? lastRewardTimestamp
                : c.lastUpdate;
            uint256 cappedElapsed = capTs - c.lastUpdate;
            uint256 cappedScore = c.accumulatedScore + uint256(c.balance) * cappedElapsed;
            if (cappedScore > 0) {
                extra = (cappedScore * delta) / 1e18;
            }
        }
        return c.pendingEth + extra;
    }

    function holdScore(address user) external view returns (uint256) {
        if (!_isTracked(user)) return 0;
        Checkpoint storage c = checkpoints[user];
        uint256 elapsed = block.timestamp - c.lastUpdate;
        return c.accumulatedScore + uint256(c.balance) * elapsed;
    }

    function totalHoldScoreLive() external view returns (uint256) {
        uint256 elapsed = block.timestamp - totalLastUpdate;
        return totalAccumulatedScore + totalSettledBalance * elapsed;
    }

    function antiSnipeBpsFor(address seller) external view returns (uint256) {
        return _antiSnipeExtraBps(seller);
    }

    // ═════════════════════════════════════════════════════════════
    //  ADMIN (factory-only)
    // ═════════════════════════════════════════════════════════════

    function setSwapThreshold(uint256 newThreshold) external onlyFactory {
        require(newThreshold > 0, "Bad threshold");
        swapThreshold = newThreshold;
    }

    function setExcluded(address account, bool excluded) external onlyFactory {
        isExcluded[account] = excluded;
    }

    /**
     * @notice Set or rotate the keeper address that is allowed to call pushRewards().
     *         Only callable by factory (which restricts it to the platform owner).
     *         Set to address(0) to disable push distribution (holders use claim()).
     */
    function setKeeper(address newKeeper) external onlyFactory {
        emit KeeperUpdated(keeper, newKeeper);
        keeper = newKeeper;
    }

    // Accept ETH from curve/router
    receive() external payable {}
}

contracts/v2/interfaces/IUniswapV2Router.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

interface IUniswapV2Router02 {
    function factory() external pure returns (address);
    function WETH() external pure returns (address);

    function addLiquidityETH(
        address token,
        uint256 amountTokenDesired,
        uint256 amountTokenMin,
        uint256 amountETHMin,
        address to,
        uint256 deadline
    ) external payable returns (uint256 amountToken, uint256 amountETH, uint256 liquidity);

    function swapExactTokensForETHSupportingFeeOnTransferTokens(
        uint256 amountIn,
        uint256 amountOutMin,
        address[] calldata path,
        address to,
        uint256 deadline
    ) external;

    function getAmountsOut(uint256 amountIn, address[] calldata path)
        external
        view
        returns (uint256[] memory amounts);
}

interface IUniswapV2Factory {
    function createPair(address tokenA, address tokenB) external returns (address pair);
